    for (i = touchedText.length - 1; i >= 0; i--) touchedText[i].node.nodeValue = touchedText[i].en;
    for (i = touchedAttr.length - 1; i >= 0; i--) touchedAttr[i].el.setAttribute(touchedAttr[i].attr, touchedAttr[i].en);
    touchedText = []; touchedAttr = [];
